import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { bookingsAPI, adminAPI, servicesAPI } from '../../utils/api';
import { FiUsers, FiBookOpen, FiDollarSign, FiTrendingUp, FiEdit2, FiChevronRight, FiPlus } from 'react-icons/fi';
import { HiSparkles } from 'react-icons/hi2';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [stats, setStats] = useState(null);
  const [recentBookings, setRecentBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    const load = async () => {
      try {
        const { data } = await bookingsAPI.adminGetStats();
        setStats(data.stats);
        setRecentBookings(data.recentBookings || []);
      } catch (e) { toast.error('Failed to load stats'); }
      setLoading(false);
    };
    load();
  }, []);

  const statCards = stats ? [
    { label: 'Total Bookings', value: stats.totalBookings, icon: '📋', color: 'var(--primary)', bg: 'var(--primary-light)' },
    { label: 'Pending', value: stats.pendingBookings, icon: '⏳', color: '#F59E0B', bg: '#FEF9C3' },
    { label: 'Completed', value: stats.completedBookings, icon: '✅', color: 'var(--success)', bg: '#DCFCE7' },
    { label: 'Total Users', value: stats.totalUsers, icon: '👥', color: '#6366F1', bg: '#EEF2FF' },
    { label: 'Total Services', value: stats.totalServices, icon: '🛠️', color: '#14B8A6', bg: '#CCFBF1' },
    { label: 'Revenue', value: `₹${(stats.totalRevenue / 100).toFixed(0)}`, icon: '💰', color: '#EC4899', bg: '#FCE7F3' },
  ] : [];

  const adminTabs = [
    { id: 'overview', label: 'Overview' },
    { id: 'bookings', label: 'Bookings' },
    { id: 'users', label: 'Users' },
    { id: 'services', label: 'Services' },
  ];

  return (
    <div className="main-content" style={{ background: 'var(--bg)', minHeight: '100vh' }}>
      {/* Header */}
      <div style={{ background: 'linear-gradient(135deg, #0F0C29, #302B63)', padding: '48px 0 32px' }}>
        <div className="container" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', flexWrap: 'wrap', gap: 16 }}>
          <div style={{ color: 'white' }}>
            <div style={{ color: 'rgba(255,255,255,0.6)', marginBottom: 4 }}>Admin Panel</div>
            <h1 style={{ fontSize: 28, fontWeight: 900, fontFamily: 'var(--font-display)' }}>🛡️ Dashboard</h1>
          </div>
          <div style={{ display: 'flex', gap: 10 }}>
            <Link to="/admin/services/new" className="btn btn-sm" style={{ background: 'var(--primary)', color: 'white', gap: 6 }}>
              <FiPlus /> Add Service
            </Link>
          </div>
        </div>
      </div>

      <div className="container" style={{ padding: '0 24px 40px' }}>
        {/* Stat cards */}
        {!loading && (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: 16, marginTop: -28, marginBottom: 32 }}>
            {statCards.map(s => (
              <div key={s.label} className="card" style={{ padding: '20px', background: 'white', cursor: 'default' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div>
                    <div style={{ fontSize: 13, color: 'var(--text-secondary)', fontWeight: 600, marginBottom: 8 }}>{s.label}</div>
                    <div style={{ fontSize: 28, fontWeight: 900, color: s.color, fontFamily: 'var(--font-display)' }}>{s.value}</div>
                  </div>
                  <div style={{ width: 44, height: 44, borderRadius: 'var(--radius-md)', background: s.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20 }}>
                    {s.icon}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Tabs */}
        <div style={{ display: 'flex', gap: 4, marginBottom: 24, background: 'var(--surface2)', padding: 4, borderRadius: 'var(--radius-lg)', width: 'fit-content', flexWrap: 'wrap' }}>
          {adminTabs.map(t => (
            <button key={t.id} onClick={() => setActiveTab(t.id)} style={{
              padding: '10px 20px', borderRadius: 'var(--radius-md)', border: 'none', cursor: 'pointer',
              background: activeTab === t.id ? 'white' : 'transparent',
              color: activeTab === t.id ? 'var(--primary)' : 'var(--text-secondary)',
              fontWeight: 600, fontSize: 14, boxShadow: activeTab === t.id ? 'var(--shadow-sm)' : 'none',
              transition: 'all 0.2s', fontFamily: 'var(--font-display)'
            }}>{t.label}</button>
          ))}
        </div>

        {activeTab === 'overview' && <AdminOverview recentBookings={recentBookings} navigate={navigate} loading={loading} />}
        {activeTab === 'bookings' && <AdminBookings />}
        {activeTab === 'users' && <AdminUsers />}
        {activeTab === 'services' && <AdminServices navigate={navigate} />}
      </div>
    </div>
  );
}

